<?php
declare(strict_types=1);
require_once __DIR__.'/auth.php';require_once __DIR__.'/permissions.php';require_once __DIR__.'/admin_notification_service.php';require_once __DIR__.'/audit.php';require_once __DIR__.'/config/services.php';require_once __DIR__.'/imap_config.php';require_once __DIR__.'/avatar.php';

function esAdministracionComunicacionAtenea():bool{return ($_SESSION['usuario_rol']??'')==='admin'||(esRolAdministradorDocenteAtenea((string)($_SESSION['usuario_rol']??''))&&modoHibridoActualAtenea()==='admin'&&usuarioTienePermiso('communications.view'));}
function exigirComunicacionHibridaAtenea(bool $escritura=false):void{if(!esRolAdministradorDocenteAtenea((string)($_SESSION['usuario_rol']??'')))return;$modo=modoHibridoActualAtenea();if($modo==='admin')exigirPermiso($escritura?'communications.reply':'communications.view');else{exigirModoHibridoAtenea('docente');exigirPermiso('academic.communications.send');}}

function comunicacionUsuario(PDO $pdo,int $id):?array{$q=$pdo->prepare("SELECT id,nombre,apellido,correo,rol,foto FROM usuarios WHERE id=:id AND estado='activo' AND deleted_at IS NULL");$q->execute(['id'=>$id]);$u=$q->fetch()?:null;if($u&&esRolAdministradorDocenteAtenea((string)$u['rol']))$u['rol']=$id===(int)($_SESSION['usuario_id']??0)&&modoHibridoActualAtenea()==='docente'?'docente':'admin';return$u;}
function etiquetaRolComunicacion(string $rol):string{return match($rol){'usuario'=>'Estudiante','docente'=>'Docente','administracion_docente','administrador_docente'=>'Administrador docente','admin'=>'Administración',default=>'Usuario'};}

function contactoComunicacionPermitido(PDO $pdo,int $actor,int $contacto):bool
{
 if($actor===$contacto)return false;$a=comunicacionUsuario($pdo,$actor);$c=comunicacionUsuario($pdo,$contacto);if(!$a||!$c)return false;if($a['rol']==='admin'||$c['rol']==='admin')return true;
 if($a['rol']==='docente'){if($c['rol']==='docente')return true;$q=$pdo->prepare("SELECT 1 FROM capacitacion_secciones s JOIN inscripciones_capacitacion i ON i.seccion_id=s.id AND i.estado IN('inscrito','finalizado') WHERE s.docente_id=:a AND i.usuario_id=:c LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}
 if($a['rol']==='usuario'&&$c['rol']==='docente'){$q=$pdo->prepare("SELECT 1 FROM inscripciones_capacitacion i JOIN capacitacion_secciones s ON s.id=i.seccion_id WHERE i.usuario_id=:a AND s.docente_id=:c AND i.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}
 if($a['rol']==='usuario'&&$c['rol']==='usuario'){$q=$pdo->prepare("SELECT 1 FROM inscripciones_capacitacion i1 JOIN inscripciones_capacitacion i2 ON i2.seccion_id=i1.seccion_id AND i2.usuario_id=:c AND i2.estado IN('inscrito','finalizado') WHERE i1.usuario_id=:a AND i1.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['a'=>$actor,'c'=>$contacto]);return(bool)$q->fetchColumn();}return false;
}

function agendaComunicacion(PDO $pdo,int $actor,array $filtros=[]):array
{
 $yo=comunicacionUsuario($pdo,$actor);if(!$yo)return[];$where=["u.id<>:actor","u.estado='activo'","u.deleted_at IS NULL"];$p=['actor'=>$actor];$rol=$filtros['rol']??'';if(in_array($rol,['usuario','docente','administracion_docente','admin'],true)){$where[]='u.rol=:rol';$p['rol']=$rol;}$qtxt=trim((string)($filtros['q']??''));if($qtxt!==''){$where[]="(CONCAT_WS(' ',u.nombre,u.apellido) LIKE :q1 OR u.correo LIKE :q2)";$p['q1']=$p['q2']='%'.$qtxt.'%';}$cap=(int)($filtros['capacitacion']??0);if($cap){$where[]="EXISTS(SELECT 1 FROM inscripciones_capacitacion ia LEFT JOIN capacitacion_secciones sa ON sa.id=ia.seccion_id WHERE ia.asignatura_id=:cap AND (ia.usuario_id=u.id OR sa.docente_id=u.id))";$p['cap']=$cap;}$sec=(int)($filtros['seccion']??0);if($sec){$where[]="EXISTS(SELECT 1 FROM inscripciones_capacitacion isec JOIN capacitacion_secciones ss ON ss.id=isec.seccion_id WHERE isec.seccion_id=:sec AND (isec.usuario_id=u.id OR ss.docente_id=u.id))";$p['sec']=$sec;}
 $q=$pdo->prepare('SELECT u.id,u.nombre,u.apellido,u.correo,u.rol FROM usuarios u WHERE '.implode(' AND ',$where).' ORDER BY u.rol,u.nombre,u.apellido LIMIT 300');$q->execute($p);return array_values(array_filter($q->fetchAll(),fn($c)=>contactoComunicacionPermitido($pdo,$actor,(int)$c['id'])));
}

function chatUsuarioBloqueado(PDO $pdo,int $usuario):bool{$q=$pdo->prepare('SELECT 1 FROM chat_bloqueos WHERE usuario_id=:u AND desbloqueado_at IS NULL');$q->execute(['u'=>$usuario]);return(bool)$q->fetchColumn();}
function abrirChatIndividual(PDO $pdo,int $actor,int $contacto):int
{
 if(!contactoComunicacionPermitido($pdo,$actor,$contacto))throw new DomainException('No tienes permiso para contactar a este usuario.');$ids=[$actor,$contacto];sort($ids,SORT_NUMERIC);$clave=hash('sha256',$ids[0].':'.$ids[1]);$pdo->beginTransaction();try{$q=$pdo->prepare("INSERT INTO chat_conversaciones(clave_individual,creado_por) VALUES(:k,:u) ON DUPLICATE KEY UPDATE id=LAST_INSERT_ID(id)");$q->execute(['k'=>$clave,'u'=>$actor]);$id=(int)$pdo->lastInsertId();$q=$pdo->prepare('INSERT IGNORE INTO chat_participantes(conversacion_id,usuario_id) VALUES(:c,:u)');foreach($ids as$u)$q->execute(['c'=>$id,'u'=>$u]);$pdo->commit();return$id;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}
}
function chatParticipa(PDO $pdo,int $conversacion,int $usuario):bool{$q=$pdo->prepare('SELECT 1 FROM chat_participantes WHERE conversacion_id=:c AND usuario_id=:u AND archivado_at IS NULL');$q->execute(['c'=>$conversacion,'u'=>$usuario]);return(bool)$q->fetchColumn();}
function textoChatSeguro(string $texto):string{$texto=trim(strip_tags($texto));$texto=preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F]/u','',$texto)??'';return mb_substr($texto,0,5000);}
function alertarChatAdministrativoAtenea(PDO $pdo,int $conversacion,int $mensajeId,int $actor,string $texto):void
{
 try{$q=$pdo->prepare('SELECT u.id,u.nombre,u.apellido,u.correo,u.rol,u.es_superadmin FROM chat_participantes p JOIN usuarios u ON u.id=p.usuario_id WHERE p.conversacion_id=:c AND p.archivado_at IS NULL ORDER BY u.id');$q->execute(['c'=>$conversacion]);$participantes=$q->fetchAll();if(count($participantes)!==2)return;$autor=null;$destino=null;foreach($participantes as$participante){if((int)$participante['id']===$actor)$autor=$participante;else$destino=$participante;}if(!$autor||!$destino)return;$resumen=mb_substr($texto?:'Se adjuntó un archivo.',0,500);$enlace=atenea_url('src/comunicaciones/chat.php?id='.$conversacion);if($autor['rol']==='admin'&&esRolAdministradorDocenteAtenea((string)$destino['rol'])){enviarPlantillaCorreoAtenea('aviso_administrativo',(string)$destino['correo'],trim((string)$destino['nombre'].' '.(string)$destino['apellido']),['asunto'=>'Nuevo mensaje administrativo en Atenea','resumen'=>'Tienes un mensaje directo del administrador.','mensaje'=>$resumen,'enlace'=>atenea_url_absoluta('src/comunicaciones/chat.php?id='.$conversacion),'texto_boton'=>'Abrir conversación'],['usuario_id'=>(int)$destino['id'],'evento_id'=>'hybrid-chat:'.$mensajeId,'idempotency_key'=>'hybrid-chat:'.$mensajeId]);}elseif(esRolAdministradorDocenteAtenea((string)$autor['rol'])&&$destino['rol']==='admin'&&(int)$destino['es_superadmin']===1){notificarAdministracionAtenea('mensaje_hibrido','Mensaje de administrador docente',$resumen,'informacion',$actor,$enlace,'hybrid-chat:'.$mensajeId,['category'=>'comunicaciones','created_by'=>$actor,'skip_internal'=>true],$pdo);}}catch(Throwable$alerta){error_log('Alerta de chat híbrido: '.$alerta->getMessage());}
}
function enviarMensajeChat(PDO $pdo,int $conversacion,int $actor,string $texto,?int $respuestaA=null,?array $adjunto=null,?string $idempotencia=null):int
{
 $texto=textoChatSeguro($texto);if($texto===''&&!$adjunto)throw new DomainException('Escribe un mensaje o adjunta un archivo.');if(!chatParticipa($pdo,$conversacion,$actor))throw new DomainException('La conversación no te pertenece.');if(chatUsuarioBloqueado($pdo,$actor))throw new DomainException('Tu acceso al chat está bloqueado.');$q=$pdo->prepare('SELECT usuario_id FROM chat_participantes WHERE conversacion_id=:c AND usuario_id<>:u AND archivado_at IS NULL');$q->execute(['c'=>$conversacion,'u'=>$actor]);$destinos=array_map('intval',$q->fetchAll(PDO::FETCH_COLUMN));if(!$destinos)throw new DomainException('La conversación ya no tiene un destinatario activo.');foreach($destinos as$destino)if(!contactoComunicacionPermitido($pdo,$actor,$destino))throw new DomainException('La relación actual ya no permite enviar mensajes.');if($respuestaA){$q=$pdo->prepare("SELECT 1 FROM chat_mensajes WHERE id=:id AND conversacion_id=:c AND estado='activo'");$q->execute(['id'=>$respuestaA,'c'=>$conversacion]);if(!$q->fetchColumn())throw new DomainException('El mensaje al que respondes ya no está disponible.');}$idempotencia=$idempotencia&&preg_match('/^[a-f0-9]{64}$/',$idempotencia)?$idempotencia:null;if($idempotencia){$q=$pdo->prepare('SELECT id FROM chat_mensajes WHERE idempotency_key=:k AND conversacion_id=:c AND remitente_id=:u');$q->execute(['k'=>$idempotencia,'c'=>$conversacion,'u'=>$actor]);if($previo=$q->fetchColumn())return(int)$previo;}
 $pdo->beginTransaction();try{$q=$pdo->prepare("INSERT INTO chat_mensajes(conversacion_id,remitente_id,respuesta_a_id,contenido,idempotency_key) VALUES(:c,:u,:r,:m,:k)");$q->execute(['c'=>$conversacion,'u'=>$actor,'r'=>$respuestaA,'m'=>$texto,'k'=>$idempotencia]);$id=(int)$pdo->lastInsertId();if($adjunto){$q=$pdo->prepare('INSERT INTO chat_adjuntos(mensaje_id,archivo_relpath,archivo_nombre,archivo_mime,archivo_tamano,es_imagen) VALUES(:m,:r,:n,:mime,:t,:imagen)');$q->execute(['m'=>$id,'r'=>$adjunto['relpath'],'n'=>$adjunto['nombre'],'mime'=>$adjunto['mime'],'t'=>$adjunto['tamano'],'imagen'=>str_starts_with($adjunto['mime'],'image/')?1:0]);}$pdo->prepare('INSERT INTO chat_lecturas(mensaje_id,usuario_id) VALUES(:m,:u)')->execute(['m'=>$id,'u'=>$actor]);$pdo->prepare('UPDATE chat_conversaciones SET ultimo_mensaje_at=NOW() WHERE id=:c')->execute(['c'=>$conversacion]);foreach($destinos as$destino)crearNotificacionAtenea(['usuario_id'=>$destino,'created_by'=>$actor,'tipo'=>'chat_nuevo','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Nuevo mensaje interno','descripcion'=>mb_substr($texto?:'Archivo adjunto',0,160),'url'=>atenea_url('src/comunicaciones/chat.php?id='.$conversacion),'idempotency_key'=>'chat:mensaje:'.$id],$pdo);registrarAuditoria(['actor_user_id'=>$actor,'target_user_id'=>$destinos[0]??null,'event_type'=>'chat.message.sent','module'=>'communications','entity_type'=>'chat_message','entity_id'=>$id,'action'=>'create','description'=>'Mensaje interno enviado.'],$pdo);$pdo->commit();alertarChatAdministrativoAtenea($pdo,$conversacion,$id,$actor,$texto);return$id;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}
}
function marcarChatLeido(PDO $pdo,int $conversacion,int $usuario):void{if(!chatParticipa($pdo,$conversacion,$usuario))throw new DomainException('Acceso denegado.');$pdo->prepare('INSERT IGNORE INTO chat_lecturas(mensaje_id,usuario_id) SELECT id,:u FROM chat_mensajes WHERE conversacion_id=:c AND remitente_id<>:u2')->execute(['u'=>$usuario,'c'=>$conversacion,'u2'=>$usuario]);$pdo->prepare('UPDATE chat_participantes SET ultimo_leido_mensaje_id=(SELECT MAX(id) FROM chat_mensajes WHERE conversacion_id=:c) WHERE conversacion_id=:c2 AND usuario_id=:u')->execute(['c'=>$conversacion,'c2'=>$conversacion,'u'=>$usuario]);}

function conversacionesChatAtenea(PDO $pdo,int $actor,string $buscar=''):array
{
 $pdo->prepare("UPDATE chat_mensajes m JOIN chat_participantes p ON p.conversacion_id=m.conversacion_id AND p.usuario_id=:u AND p.archivado_at IS NULL SET m.entregado_at=COALESCE(m.entregado_at,NOW()) WHERE m.remitente_id<>:u2 AND m.estado='activo'")->execute(['u'=>$actor,'u2'=>$actor]);$sql="SELECT c.id,c.ultimo_mensaje_at,u.id contacto_id,u.nombre,u.apellido,u.rol,u.foto,(SELECT CASE WHEN m.estado='eliminado' THEN 'Mensaje eliminado' WHEN m.contenido<>'' THEN m.contenido ELSE 'Archivo adjunto' END FROM chat_mensajes m WHERE m.conversacion_id=c.id ORDER BY m.id DESC LIMIT 1) ultimo,(SELECT COUNT(*) FROM chat_mensajes m LEFT JOIN chat_lecturas l ON l.mensaje_id=m.id AND l.usuario_id=:lector WHERE m.conversacion_id=c.id AND m.remitente_id<>:actor2 AND m.estado='activo' AND l.mensaje_id IS NULL) no_leidos FROM chat_conversaciones c JOIN chat_participantes p ON p.conversacion_id=c.id AND p.usuario_id=:actor3 AND p.archivado_at IS NULL JOIN chat_participantes po ON po.conversacion_id=c.id AND po.usuario_id<>:actor4 AND po.archivado_at IS NULL JOIN usuarios u ON u.id=po.usuario_id AND u.estado='activo' AND u.deleted_at IS NULL WHERE c.estado='activa'";$params=['lector'=>$actor,'actor2'=>$actor,'actor3'=>$actor,'actor4'=>$actor];if($buscar!==''){$sql.=" AND CONCAT_WS(' ',u.nombre,u.apellido) LIKE :buscar";$params['buscar']='%'.mb_substr($buscar,0,100).'%';}$sql.=' ORDER BY COALESCE(c.ultimo_mensaje_at,c.created_at) DESC,c.id DESC LIMIT 200';$q=$pdo->prepare($sql);$q->execute($params);$filas=$q->fetchAll();foreach($filas as&$f){$f['contacto']=trim($f['nombre'].' '.$f['apellido']);$f['avatar']=urlAvatarAtenea($f);$f['rol_etiqueta']=etiquetaRolComunicacion($f['rol']);$f['no_leidos']=(int)$f['no_leidos'];}unset($f);return$filas;
}

function mensajesChatAtenea(PDO $pdo,int $conversacion,int $actor,?int $antes=null,?int $despues=null,int $limite=40):array
{
 if(!chatParticipa($pdo,$conversacion,$actor))throw new DomainException('No tienes acceso a esta conversación.');$limite=max(1,min(60,$limite));$where=['m.conversacion_id=:c'];$params=['c'=>$conversacion];if($antes){$where[]='m.id<:antes';$params['antes']=$antes;}if($despues){$where[]='m.id>:despues';$params['despues']=$despues;}$orden=$despues?'ASC':'DESC';$sql="SELECT m.*,CONCAT(u.nombre,' ',u.apellido) remitente,u.foto,r.contenido respuesta_contenido,CONCAT(ru.nombre,' ',ru.apellido) respuesta_remitente,(SELECT COUNT(*) FROM chat_lecturas l WHERE l.mensaje_id=m.id AND l.usuario_id<>m.remitente_id) lecturas_otro FROM chat_mensajes m JOIN usuarios u ON u.id=m.remitente_id LEFT JOIN chat_mensajes r ON r.id=m.respuesta_a_id LEFT JOIN usuarios ru ON ru.id=r.remitente_id WHERE ".implode(' AND ',$where)." ORDER BY m.id $orden LIMIT $limite";$q=$pdo->prepare($sql);$q->execute($params);$mensajes=$q->fetchAll();if(!$despues)$mensajes=array_reverse($mensajes);$ids=array_map(static fn($m)=>(int)$m['id'],$mensajes);$adjuntos=[];if($ids){$marks=implode(',',array_fill(0,count($ids),'?'));$q=$pdo->prepare("SELECT * FROM chat_adjuntos WHERE mensaje_id IN($marks) ORDER BY id");$q->execute($ids);foreach($q->fetchAll()as$a){$a['url']=atenea_url('src/comunicaciones/chat-adjunto.php?id='.(int)$a['id']);$adjuntos[(int)$a['mensaje_id']][]=$a;}}foreach($mensajes as&$m){$propio=(int)$m['remitente_id']===$actor;$m['propio']=$propio;$m['avatar']=urlAvatarAtenea(['foto'=>$m['foto'],'nombre'=>$m['remitente']]);$m['adjuntos']=$m['estado']==='eliminado'?[]:($adjuntos[(int)$m['id']]??[]);$m['estado_envio']=$propio?((int)$m['lecturas_otro']>0?'leido':(!empty($m['entregado_at'])?'entregado':'enviado')):'';$m['puede_eliminar']=(($_SESSION['usuario_rol']??'')==='admin'||($propio&&strtotime($m['created_at'])>=time()-900))&&$m['estado']!=='eliminado';$m['puede_reportar']=!$propio&&$m['estado']==='activo';}unset($m);return$mensajes;
}

function marcarChatEntregadoAtenea(PDO $pdo,int $conversacion,int $actor):void{$q=$pdo->prepare("UPDATE chat_mensajes SET entregado_at=COALESCE(entregado_at,NOW()) WHERE conversacion_id=:c AND remitente_id<>:u AND estado='activo'");$q->execute(['c'=>$conversacion,'u'=>$actor]);}
function eliminarMensajeChatAtenea(PDO $pdo,int $mensajeId,int $actor):void{$q=$pdo->prepare('SELECT conversacion_id,remitente_id,created_at,estado FROM chat_mensajes WHERE id=:id');$q->execute(['id'=>$mensajeId]);$m=$q->fetch();if(!$m||!chatParticipa($pdo,(int)$m['conversacion_id'],$actor))throw new DomainException('El mensaje no existe.');$admin=($_SESSION['usuario_rol']??'')==='admin';if(!$admin&&((int)$m['remitente_id']!==$actor||strtotime($m['created_at'])<time()-900))throw new DomainException('Ya no puedes eliminar este mensaje.');$pdo->prepare("UPDATE chat_mensajes SET contenido='',estado='eliminado',eliminado_at=NOW(),eliminado_por=:u WHERE id=:id")->execute(['u'=>$actor,'id'=>$mensajeId]);registrarAuditoria(['actor_user_id'=>$actor,'event_type'=>'chat.message.deleted','module'=>'communications','entity_type'=>'chat_message','entity_id'=>$mensajeId,'action'=>'delete','description'=>'Mensaje eliminado según permisos.'],$pdo);}

function almacenamientoComunicacionBase():string{return rtrim(AppConfig::value('COMMUNICATION_STORAGE_PATH',dirname(ATENEA_ROOT).'/atenea-private/comunicaciones'),'/\\');}
function rutaPrivadaComunicacion(string $rel):?string{if($rel===''||str_contains($rel,'..')||preg_match('/[^A-Za-z0-9_\/.\-]/',$rel))return null;$base=almacenamientoComunicacionBase();$root=realpath($base);$ruta=realpath($base.DIRECTORY_SEPARATOR.str_replace('/',DIRECTORY_SEPARATOR,$rel));return$root&&$ruta&&str_starts_with(strtolower($ruta),strtolower($root.DIRECTORY_SEPARATOR))&&is_file($ruta)?$ruta:null;}
function guardarAdjuntoComunicacion(string $campo,string $carpeta='adjuntos'):?array{if(!isset($_FILES[$campo])||($_FILES[$campo]['error']??UPLOAD_ERR_NO_FILE)===UPLOAD_ERR_NO_FILE)return null;$f=$_FILES[$campo];if($f['error']!==UPLOAD_ERR_OK||(int)$f['size']<1||(int)$f['size']>10*1024*1024)throw new DomainException('Adjunto vacío o mayor de 10 MB.');$permitidos=['application/pdf'=>'pdf','application/msword'=>'doc','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp','text/plain'=>'txt'];$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);if(!isset($permitidos[$mime]))throw new DomainException('Tipo de adjunto no permitido.');$ext=strtolower(pathinfo((string)$f['name'],PATHINFO_EXTENSION));$validas=$permitidos[$mime]==='jpg'?['jpg','jpeg']:[$permitidos[$mime]];if(!in_array($ext,$validas,true)||preg_match('/\.(php\d*|phtml|phar|html?|svg|exe|js|sh)(\.|$)/i',(string)$f['name']))throw new DomainException('La extensión del adjunto no es segura.');$dir=almacenamientoComunicacionBase().DIRECTORY_SEPARATOR.$carpeta;if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))throw new RuntimeException('No se pudo crear el almacenamiento privado.');$nombre=bin2hex(random_bytes(24)).'.'.$permitidos[$mime];if(!move_uploaded_file($f['tmp_name'],$dir.DIRECTORY_SEPARATOR.$nombre))throw new RuntimeException('No se pudo guardar el adjunto.');return['relpath'=>$carpeta.'/'.$nombre,'nombre'=>mb_substr(basename((string)$f['name']),0,190),'mime'=>$mime,'tamano'=>(int)$f['size']];}

function decodificarCabeceraImap(string $valor):string{if(function_exists('imap_mime_header_decode')){$salida='';foreach(imap_mime_header_decode($valor) as$p)$salida.=$p->text;return mb_substr(trim($salida),0,190);}return mb_substr(trim($valor),0,190);}
function guardarAdjuntosImapAtenea(mixed $imap,int $numero,mixed $estructura,int $mensajeId,PDO $pdo,string $prefijo=''):void
{
 $partes=$estructura->parts??[];foreach($partes as$i=>$parte){$n=$prefijo===''?(string)($i+1):$prefijo.'.'.($i+1);if(!empty($parte->parts)){guardarAdjuntosImapAtenea($imap,$numero,$parte,$mensajeId,$pdo,$n);continue;}$nombre='';foreach(array_merge($parte->dparameters??[],$parte->parameters??[]) as$p)if(in_array(strtolower((string)($p->attribute??'')),['filename','name'],true))$nombre=decodificarCabeceraImap((string)$p->value);if($nombre==='')continue;$sub=strtolower((string)($parte->subtype??''));$tipo=(int)($parte->type??0);$mime=match($tipo){0=>'text/'.$sub,2=>'message/'.$sub,3=>'application/'.$sub,4=>'audio/'.$sub,5=>'image/'.$sub,6=>'video/'.$sub,default=>'application/octet-stream'};$permitidos=['application/pdf'=>'pdf','application/msword'=>'doc','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp','text/plain'=>'txt'];if(!isset($permitidos[$mime]))continue;$datos=(string)imap_fetchbody($imap,$numero,$n,FT_PEEK);if((int)($parte->encoding??0)===3)$datos=base64_decode($datos,true)?:'';elseif((int)($parte->encoding??0)===4)$datos=quoted_printable_decode($datos);if($datos===''||strlen($datos)>10*1024*1024)continue;$dir=almacenamientoComunicacionBase().DIRECTORY_SEPARATOR.'correo';if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))continue;$archivo=bin2hex(random_bytes(24)).'.'.$permitidos[$mime];if(file_put_contents($dir.DIRECTORY_SEPARATOR.$archivo,$datos,LOCK_EX)===false)continue;$q=$pdo->prepare('INSERT INTO correo_centro_adjuntos(mensaje_id,archivo_relpath,archivo_nombre,archivo_mime,archivo_tamano) VALUES(:m,:r,:n,:mime,:t)');$q->execute(['m'=>$mensajeId,'r'=>'correo/'.$archivo,'n'=>mb_substr(basename($nombre),0,190),'mime'=>$mime,'t'=>strlen($datos)]);}
}
function sincronizarImapAteneaLegacy(PDO $pdo):array
{
 if(!imapAteneaConfigurado())throw new RuntimeException('IMAP no está configurado o la extensión PHP IMAP no está habilitada.');$c=configuracionImapAtenea();$flags=$c['encryption']==='none'?'/novalidate-cert':'/'.$c['encryption'];$buzon='{'.$c['host'].':'.$c['port'].'/imap'.$flags.'}'.$c['folder'];$imap=@imap_open($buzon,$c['user'],$c['password'],0,1);if(!$imap){$error=mb_substr((string)imap_last_error(),0,500);$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_error,ultima_sincronizacion_at) VALUES(:c,:e,NOW()) ON DUPLICATE KEY UPDATE ultimo_error=:e2,ultima_sincronizacion_at=NOW()")->execute(['c'=>$c['folder'],'e'=>$error,'e2'=>$error]);throw new RuntimeException('No fue posible conectar con IMAP: '.$error);}$q=$pdo->prepare('SELECT ultimo_uid FROM correo_imap_estado WHERE carpeta=:c');$q->execute(['c'=>$c['folder']]);$ultimo=(int)$q->fetchColumn();$uids=imap_search($imap,'UID '.($ultimo+1).':*',SE_UID)?:[];$nuevos=0;foreach($uids as$uid){if((int)$uid<=$ultimo)continue;$num=imap_msgno($imap,(int)$uid);$h=imap_headerinfo($imap,$num);$from=strtolower((string)($h->from[0]->mailbox??'').'@'.(string)($h->from[0]->host??''));$to=strtolower((string)($h->to[0]->mailbox??'').'@'.(string)($h->to[0]->host??''));$asunto=decodificarCabeceraImap((string)($h->subject??'Sin asunto'));$messageId=trim((string)($h->message_id??''))?:null;$body=(string)imap_fetchbody($imap,$num,'1',FT_PEEK);if($body==='')$body=(string)imap_body($imap,$num,FT_PEEK);if((int)($h->encoding??0)===3)$body=base64_decode($body,true)?:$body;elseif((int)($h->encoding??0)===4)$body=quoted_printable_decode($body);$body=mb_substr(trim(strip_tags($body)),0,100000);$q=$pdo->prepare('SELECT id FROM usuarios WHERE LOWER(correo)=:c LIMIT 1');$q->execute(['c'=>$from]);$usuario=$q->fetchColumn()?:null;$pdo->beginTransaction();try{$q=$pdo->prepare('INSERT INTO correo_centro_hilos(asunto,usuario_relacionado_id,ultimo_mensaje_at) VALUES(:a,:u,NOW())');$q->execute(['a'=>$asunto,'u'=>$usuario]);$hilo=(int)$pdo->lastInsertId();$q=$pdo->prepare("INSERT IGNORE INTO correo_centro_mensajes(hilo_id,direccion,remitente,destinatario,asunto,contenido_texto,message_id_servidor,uid_imap,carpeta_imap,estado,enviado_recibido_at) VALUES(:h,'entrada',:r,:d,:a,:m,:mid,:uid,:carpeta,'recibido',FROM_UNIXTIME(:fecha))");$q->execute(['h'=>$hilo,'r'=>$from,'d'=>$to,'a'=>$asunto,'m'=>$body?:'[Mensaje sin contenido de texto]','mid'=>$messageId,'uid'=>$uid,'carpeta'=>$c['folder'],'fecha'=>(int)($h->udate??time())]);if($q->rowCount()===0)$pdo->prepare('DELETE FROM correo_centro_hilos WHERE id=:h')->execute(['h'=>$hilo]);else{$mensajeCorreo=(int)$pdo->lastInsertId();guardarAdjuntosImapAtenea($imap,$num,imap_fetchstructure($imap,$num),$mensajeCorreo,$pdo);$nuevos++;if($usuario)crearNotificacionAtenea(['rol'=>'admin','tipo'=>'correo_recibido','categoria'=>'comunicaciones','nivel'=>'informacion','titulo'=>'Correo recibido: '.$asunto,'descripcion'=>mb_substr($body,0,160),'url'=>atenea_url('src/comunicaciones/correo-hilo.php?id='.$hilo),'idempotency_key'=>'imap:'.$c['folder'].':'.$uid],$pdo);}$pdo->commit();$ultimo=max($ultimo,(int)$uid);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();throw$e;}}imap_close($imap);$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_uid,ultima_sincronizacion_at,ultimo_error) VALUES(:c,:u,NOW(),NULL) ON DUPLICATE KEY UPDATE ultimo_uid=GREATEST(ultimo_uid,:u2),ultima_sincronizacion_at=NOW(),ultimo_error=NULL")->execute(['c'=>$c['folder'],'u'=>$ultimo,'u2'=>$ultimo]);return['nuevos'=>$nuevos,'ultimo_uid'=>$ultimo];
}

function sincronizarImapAtenea(PDO $pdo): array
{
    $c=ImapConfig::toArray();$imap=abrirImapAtenea();$nuevos=0;
    try{
        $q=$pdo->prepare('SELECT ultimo_uid FROM correo_imap_estado WHERE carpeta=:c');$q->execute(['c'=>$c['folder']]);$ultimo=(int)$q->fetchColumn();$uids=imap_search($imap,'UID '.($ultimo+1).':*',SE_UID)?:[];
        foreach($uids as$uid){
            if((int)$uid<=$ultimo)continue;$numero=imap_msgno($imap,(int)$uid);$cabecera=imap_headerinfo($imap,$numero);$remitente=strtolower((string)($cabecera->from[0]->mailbox??'').'@'.(string)($cabecera->from[0]->host??''));$destinatario=strtolower((string)($cabecera->to[0]->mailbox??'').'@'.(string)($cabecera->to[0]->host??''));$asunto=decodificarCabeceraImap((string)($cabecera->subject??'Sin asunto'));$messageId=trim((string)($cabecera->message_id??''))?:null;$contenido=(string)imap_fetchbody($imap,$numero,'1',FT_PEEK);if($contenido==='')$contenido=(string)imap_body($imap,$numero,FT_PEEK);$contenido=mb_substr(trim(strip_tags($contenido)),0,100000);$q=$pdo->prepare('SELECT id FROM usuarios WHERE LOWER(correo)=:correo LIMIT 1');$q->execute(['correo'=>$remitente]);$usuario=$q->fetchColumn()?:null;
            $pdo->beginTransaction();
            try{$q=$pdo->prepare('INSERT INTO correo_centro_hilos(asunto,usuario_relacionado_id,ultimo_mensaje_at) VALUES(:asunto,:usuario,NOW())');$q->execute(['asunto'=>$asunto,'usuario'=>$usuario]);$hilo=(int)$pdo->lastInsertId();$q=$pdo->prepare("INSERT IGNORE INTO correo_centro_mensajes(hilo_id,direccion,remitente,destinatario,asunto,contenido_texto,message_id_servidor,uid_imap,carpeta_imap,estado,enviado_recibido_at) VALUES(:hilo,'entrada',:remitente,:destinatario,:asunto,:contenido,:message_id,:uid,:carpeta,'recibido',FROM_UNIXTIME(:fecha))");$q->execute(['hilo'=>$hilo,'remitente'=>$remitente,'destinatario'=>$destinatario,'asunto'=>$asunto,'contenido'=>$contenido?:'[Mensaje sin contenido de texto]','message_id'=>$messageId,'uid'=>$uid,'carpeta'=>$c['folder'],'fecha'=>(int)($cabecera->udate??time())]);if($q->rowCount()===0)$pdo->prepare('DELETE FROM correo_centro_hilos WHERE id=:id')->execute(['id'=>$hilo]);else{$mensaje=(int)$pdo->lastInsertId();guardarAdjuntosImapAtenea($imap,$numero,imap_fetchstructure($imap,$numero),$mensaje,$pdo);$nuevos++;notificarAdministracionAtenea('correo_recibido','Correo recibido: '.$asunto,mb_substr($contenido,0,160),'informacion',$usuario?(int)$usuario:null,atenea_url('src/dashboard/comunicaciones/correos.php?hilo='.$hilo),'imap:'.$c['folder'].':'.$uid,['category'=>'comunicaciones'],$pdo);}$pdo->commit();$ultimo=max($ultimo,(int)$uid);}catch(Throwable $error){if($pdo->inTransaction())$pdo->rollBack();throw$error;}
        }
        $q=$pdo->prepare("INSERT INTO correo_imap_estado(carpeta,ultimo_uid,ultima_sincronizacion_at,ultimo_error) VALUES(:carpeta,:uid,NOW(),NULL) ON DUPLICATE KEY UPDATE ultimo_uid=GREATEST(ultimo_uid,:uid2),ultima_sincronizacion_at=NOW(),ultimo_error=NULL");$q->execute(['carpeta'=>$c['folder'],'uid'=>$ultimo,'uid2'=>$ultimo]);return['nuevos'=>$nuevos,'ultimo_uid'=>$ultimo];
    }finally{imap_close($imap);}
}
